var items = $input.all();
var results = [];
var now = new Date().toISOString();

for (var i = 0; i < items.length; i++) {
  var data = items[i].json;
  var title = data.title || 'Untitled';
  var link = data.link || data.url || data.guid || '';
  var summary = (data.contentSnippet || data.content || data.description || '').replace(/<[^>]*>/g, '').trim();
  if (summary.length > 600) summary = summary.substring(0, 597) + '...';
  var source = data.creator || data.author || 'Unknown';
  var text = (title + ' ' + summary).toLowerCase();
  var category = 'reference';
  var priority = 3;
  if (text.indexOf('vulnerability') >= 0 || text.indexOf('threat') >= 0 || text.indexOf('advisory') >= 0) { category = 'threat-intel'; priority = 1; }
  else if (text.indexOf('standard') >= 0 || text.indexOf('guidance') >= 0 || text.indexOf('framework') >= 0 || text.indexOf('policy') >= 0) { category = 'standards-policy'; priority = 2; }
  else if (text.indexOf('cryptograph') >= 0 || text.indexOf('encryption') >= 0 || text.indexOf('post-quantum') >= 0) { category = 'cryptography'; priority = 2; }
  else if (text.indexOf('research') >= 0 || text.indexOf('paper') >= 0 || text.indexOf('study') >= 0) { category = 'research-academic'; priority = 3; }
  else if (text.indexOf('design system') >= 0 || text.indexOf('gds') >= 0 || text.indexOf('single page') >= 0 || text.indexOf('accessibility') >= 0) { category = 'spa-design'; priority = 2; }
  results.push({ json: { title: title, url: link, summary: summary, source: source, discovered_at: now, category: category, priority: priority, note_type: 'reference-library' } });
}
var seen = {};
var unique = [];
for (var j = 0; j < results.length; j++) {
  var u = results[j].json.url;
  if (u && !seen[u]) { seen[u] = true; unique.push(results[j]); }
}
unique.sort(function(a, b) { return a.json.priority - b.json.priority; });
return unique.length > 0 ? unique : [{ json: { title: 'No new documents today', url: '', summary: '', source: 'scanner', category: 'none', priority: 9, note_type: 'reference-library', discovered_at: now } }];

var items = $('Categorise Documents').all();
var now = new Date().toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
var groups = {};
for (var i = 0; i < items.length; i++) {
  var cat = items[i].json.category || 'other';
  if (!groups[cat]) groups[cat] = [];
  groups[cat].push(items[i].json);
}
var labels = { 'threat-intel': 'Threat Intelligence & Advisories (Priority)', 'standards-policy': 'Standards, Policy & Guidance', 'cryptography': 'Cryptography & Encryption', 'spa-design': 'SPA Design, GDS & Accessibility', 'research-academic': 'Research Papers & Analysis', 'reference': 'Reference Materials', 'none': 'No new items' };
var colors = { 'threat-intel': '#e74c3c', 'standards-policy': '#3498db', 'cryptography': '#9b59b6', 'spa-design': '#1abc9c', 'research-academic': '#f39c12', 'reference': '#95a5a6', 'none': '#bdc3c7' };
var html = '<div style="font-family:Arial,sans-serif;max-width:750px;margin:0 auto;"><h1 style="color:#2c3e50;">HMGCC SPA - Research Library Update</h1>';
html += '<p style="color:#666;">' + now + ' - ' + items.length + ' documents processed</p><hr>';
var categoryOrder = ['threat-intel', 'standards-policy', 'cryptography', 'spa-design', 'research-academic', 'reference', 'none'];
for (var c = 0; c < categoryOrder.length; c++) {
  var catKey = categoryOrder[c];
  if (!groups[catKey] || groups[catKey].length === 0) continue;
  var entries = groups[catKey];
  var color = colors[catKey] || '#34495e';
  html += '<h2 style="color:' + color + ';border-bottom:2px solid ' + color + ';padding-bottom:5px;">' + (labels[catKey] || catKey) + ' (' + entries.length + ')</h2><ul style="list-style:none;padding:0;">';
  for (var e = 0; e < entries.length; e++) {
    html += '<li style="margin-bottom:12px;padding:10px;background:#f9f9f9;border-left:3px solid ' + color + ';border-radius:4px;">';
    if (entries[e].url) html += '<strong><a href="' + entries[e].url + '" style="color:' + color + ';">' + entries[e].title + '</a></strong>';
    else html += '<strong>' + entries[e].title + '</strong>';
    if (entries[e].summary) html += '<br><span style="color:#555;font-size:0.9em;">' + entries[e].summary.substring(0, 280) + '</span>';
    html += '<br><small style="color:#999;">Source: ' + entries[e].source + '</small></li>';
  }
  html += '</ul>';
}
html += '<hr><p style="color:#999;font-size:0.8em;">HMGCC SPA Research Library Builder - Workhorse</p></div>';
return [{ json: { subject: 'HMGCC SPA Library Update - ' + now, html: html } }];
